module sr_latch(  
    input sr_S,  
    input R,  
    output reg Q  
);  
    always @ (sr_S or R) begin  
        if (sr_S && R)  
            ; // Invalid state, do nothing  
        else if (sr_S)  
            Q = 1; // Set  
        else if (R)  
            Q = 0; // Reset  
    end  
endmodule
